package com.example.demo.controller;
import com.example.demo.dto.ProductRequest; import com.example.demo.entity.Product; import com.example.demo.service.SalesService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api") public class ProductController { private final SalesService service; public ProductController(SalesService service){this.service=service;} @GetMapping("/products") public List<Product> list(@RequestParam(required=false)String search,@RequestParam(required=false)String category){return service.products(search,category);}@GetMapping("/products/{id}") public Product one(@PathVariable long id){return service.product(id);}@GetMapping("/categories") public List<String> categories(){return service.categories();}@PostMapping("/products") public Product create(@RequestHeader("Authorization")String auth,@RequestBody ProductRequest r){return service.create(auth,r);}@PutMapping("/products/{id}") public Product update(@RequestHeader("Authorization")String auth,@PathVariable long id,@RequestBody ProductRequest r){return service.update(auth,id,r);}@DeleteMapping("/products/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@RequestHeader("Authorization")String auth,@PathVariable long id){service.delete(auth,id);} }
